// ================== CONFIG — EDITA SOLO ESTO ==================
const PHONE_NUMBER_ID = 'PONER_PHONE_NUMBER_ID'; // de Meta (WhatsApp > API Setup)
const TOKEN           = 'PONER_TOKEN';           // token de acceso de WhatsApp
const NUM_ASESOR      = '5491100000000';         // WhatsApp del asesor (sin + ni espacios)
const NUM_EQUIPO      = '5491100000000';         // WhatsApp donde avisar los pedidos de reunion
// =============================================================

const item = $input.first().json;
const body = item.body || item;
const value = body && body.entry && body.entry[0] && body.entry[0].changes
  && body.entry[0].changes[0] && body.entry[0].changes[0].value;
const msg = value && value.messages && value.messages[0];

// Si no hay mensaje (ej: acuse de recibo/estado), no hacemos nada
if (!msg) { return []; }

const from = msg.from;
let choice = '';
if (msg.type === 'interactive' && msg.interactive) {
  choice = (msg.interactive.button_reply && msg.interactive.button_reply.id)
        || (msg.interactive.list_reply && msg.interactive.list_reply.id) || '';
} else if (msg.type === 'text' && msg.text) {
  choice = (msg.text.body || '').trim().toLowerCase();
}

const txt = (to, t) => ({ messaging_product: 'whatsapp', to, type: 'text', text: { body: t } });

// Menu de bienvenida (3 botones)
const welcome = {
  messaging_product: 'whatsapp', to: from, type: 'interactive',
  interactive: {
    type: 'button',
    body: { text: '¡Hola! 👋 Soy el asistente de Estudio-C. Contanos qué necesitás y te ayudamos 👇' },
    action: { buttons: [
      { type: 'reply', reply: { id: 'btn_agendar', title: 'Agendar reunión' } },
      { type: 'reply', reply: { id: 'btn_info',    title: 'Más información' } },
      { type: 'reply', reply: { id: 'btn_asesor',  title: 'Hablar con asesor' } }
    ] }
  }
};

let reply = null;
let notify = null;

if (choice === 'btn_info' || choice === '2' || choice.includes('informacion') || choice.includes('información')) {
  // Submenu "Mas informacion" (lista de 4 opciones)
  reply = {
    messaging_product: 'whatsapp', to: from, type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: '¿Sobre qué te gustaría saber más? Elegí una opción 👇' },
      action: { button: 'Ver opciones', sections: [{
        title: 'Más información',
        rows: [
          { id: 'info_presencial',    title: 'Cursos presenciales' },
          { id: 'info_elearning',     title: 'Cursos e-learning' },
          { id: 'info_asesoramiento', title: 'Asesoramiento' },
          { id: 'info_plataformas',   title: 'Plataformas' }
        ]
      }] }
    }
  };
} else if (choice === 'btn_agendar' || choice === '1' || choice.includes('agend') || choice.includes('reuni')) {
  reply = txt(from, '¡Genial! 📅 Para coordinar una reunión, escribinos en un solo mensaje:\n\n• Tu nombre\n• El día y el horario que te quede cómodo\n\nEn breve te confirmamos. 🙌');
  notify = txt(NUM_EQUIPO, '🔔 Nuevo pedido de REUNIÓN desde el bot.\nCliente: +' + from + '\nEscribile para coordinar.');
} else if (choice === 'btn_asesor' || choice === '3' || choice.includes('asesor')) {
  reply = txt(from, '¡Perfecto! 🙋 Te paso el contacto directo de un asesor:\n\nhttps://wa.me/' + NUM_ASESOR + '\n\nEscribile por ahí y te atiende a la brevedad.');
} else if (choice === 'info_presencial') {
  reply = txt(from, '🎓 *Cursos presenciales*\n[COMPLETAR: temario, sede, días y horarios, precio.]\n\n¿Querés que te contacte un asesor? Respondé *asesor*.');
} else if (choice === 'info_elearning') {
  reply = txt(from, '💻 *Cursos e-learning*\n[COMPLETAR: plataforma, modalidad, duración, precio.]\n\n¿Querés que te contacte un asesor? Respondé *asesor*.');
} else if (choice === 'info_asesoramiento') {
  reply = txt(from, '🧭 *Asesoramiento*\n[COMPLETAR: en qué asesoran, cómo es el proceso, precio.]\n\n¿Querés que te contacte un asesor? Respondé *asesor*.');
} else if (choice === 'info_plataformas') {
  reply = txt(from, '🛠️ *Plataformas*\n[COMPLETAR: qué plataformas ofrecen o integran.]\n\n¿Querés que te contacte un asesor? Respondé *asesor*.');
} else {
  // Cualquier otro mensaje (saludo, texto libre) -> menu de bienvenida
  reply = welcome;
}

const url = 'https://graph.facebook.com/v21.0/' + PHONE_NUMBER_ID + '/messages';
return [{ json: { to: from, url, token: TOKEN, reply, notify } }];

// Verifica el handshake de Meta (hub.mode / hub.verify_token / hub.challenge)
// IMPORTANTE: este VERIFY_TOKEN tiene que ser IDENTICO al que pongas en Meta
// (WhatsApp > Configuration > Webhook > Verify token). Podes usar cualquier palabra.
const VERIFY_TOKEN = 'estudioc123';

const q = ($input.first().json.query) || {};
const ok = q['hub.mode'] === 'subscribe' && q['hub.verify_token'] === VERIFY_TOKEN;
return [{ json: { ok, challenge: q['hub.challenge'] || '' } }];
